   153→// RuleOrDie calls the binding method and panics if there is an error.
   154→func (r *PolicyRuleBuilder) RuleOrDie() PolicyRule {
   155→	ret, err := r.Rule()
   156→	if err != nil {
   157→		panic(err)
   158→	}
   159→	return ret
   160→}
